  ('dietitian-moex-01403', 'dietitian', 'dietitian-moex-109-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某大學營養科系，定期訪視社區安養機構，舉辦營養衛教活動。今年度的衛教內容為教導長者認 識鈣質、蛋白質等營養密度高的食物，以提升長者生活品質，下列何項評估可了解此目的是否 達成？', '["結果", "成本", "過程", "臨床"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "e533e754d708", "answer_pdf_sha1": "b68719737860", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
