  ('dietitian-moex-01408', 'dietitian', 'dietitian-moex-109-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '102～105年國民營養健康狀況變遷調查，維生素的營養狀況，下列敘述何者錯誤？', '["飲食中攝取的營養素缺乏最嚴重的為脂溶性維生素D及維生素E", "飲食中各年齡層維生素B 攝取狀況皆未達DRIs之建議攝取量 12", "飲食中維生素攝取狀況最差的族群為13～18歲的女性", "血液中維生素E缺乏盛行率幾近為0"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "e533e754d708", "answer_pdf_sha1": "b68719737860", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
